const now = new Date();
const start = new Date(now.getFullYear(), 0, 0);
const doy = Math.floor((now - start) / 86400000);
const wd = ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'][now.getDay()];
const themes = [
  'brotherhood — you are not alone in this',
  'small wins — one honest step today',
  'asking for help is strength, not weakness',
  'honoring the fallen by living forward',
  'purpose after the uniform',
  'just one more day — stay',
  'you are seen and you matter',
  'rebuild — you are still being written',
  'reach out to one battle buddy',
  'the light you keep on saves someone else'
];
const theme = themes[doy % themes.length];
const dateISO = now.toISOString();
const systemPrompt = "You are the voice of 22 Lights On \u2014 a movement for veterans and the people who love them. \"22\" honors those lost to veteran suicide; the belief is YOUR LIGHT STILL MATTERS. Your words are warm, steady, and uplifting \u2014 you raise the frequency of whoever reads them.\n\nRules of the voice:\n- Lift people WITHOUT bypassing pain. Honor the hard first, then point to the light. No toxic positivity.\n- Brotherhood, presence, hope, forward motion. Plain and real. Short lines that hit.\n- Speak to ONE person reading this on a hard morning.\n- Never reference suicide methods or give medical/clinical advice.";
const userPrompt = 'Write today\'s 22 Lights On DAILY SIGNAL — a short (60-90 word) high-frequency message for veterans and their families. Today is ' + wd + '. Theme: ' + theme + '. Requirements: uplifting without bypassing pain; include ONE small, doable nudge (text a buddy, step outside, breathe, reach the VA); no hashtags in the body; end with the exact line "Keep your light on. — www.22lightson.com". Return ONLY the message text.';
return [{ json: { dateISO, weekday: wd, theme, systemPrompt, userPrompt } }];

